class Solution {
public:
    long long mostPoints(vector<vector<int>>& questions) {
        int n = questions.size();
        vector<long long> dp(n);
        for (int i = n - 1; i >= 0; --i) {
            if (i + questions[i][1] < n) {
                dp[i] = questions[i][0] + max(dp[i + 1], dp[i + questions[i][1] + 1]);
            } else {
                dp[i] = questions[i][0] + dp[i + 1];
            }
        }
        return dp[0];
    }
};
